// Created: 2026-04-03

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// --- Test isolation ---
const testDir = join(tmpdir(), `ork-sink-registry-test-${process.pid}`);
let logMessages: string[] = [];

// --- Mocks ---
vi.mock('../../lib/common.js', () => mockCommonBasic({
  getSessionId: () => 'test-session',
  getCachedBranch: () => 'main',
  logHook: (_name: string, msg: string) => { logMessages.push(msg); },
  getProjectDir: () => testDir,
}));

vi.mock('../../lib/paths.js', () => ({
  getPluginDataDir: () => testDir,
  getProjectDir: () => testDir,
}));

vi.mock('../../lib/orchestration-state.js', () => ({
  getWebhookUrl: () => undefined,
}));

vi.mock('../../lib/crypto.js', () => ({
  signPayload: (body: string) => `sha256=mock-${body.length}`,
  sanitizePayload: (obj: unknown) => obj,
}));

vi.mock('../../lifecycle/usage-summary-reporter.js', () => ({
  getProjectSlug: () => 'test-project',
}));

import {
  loadPluginSinkConfigs,
  loadUserSinkConfigs,
  registerAllSinks,
} from '../../lib/sink-registry.js';
import { sinkCount, _resetSinksForTesting } from '../../lib/telemetry.js';
import { createTestContext } from '../fixtures/test-context.js';

function writePluginJson(content: object): void {
  writeFileSync(join(testDir, 'plugin.json'), JSON.stringify(content), 'utf8');
}

function writeSettingsLocalJson(content: object): void {
  const claudeDir = join(testDir, '.claude');
  mkdirSync(claudeDir, { recursive: true });
  writeFileSync(join(claudeDir, 'settings.local.json'), JSON.stringify(content), 'utf8');
}

let testCtx: ReturnType<typeof createTestContext>;
describe('Sink Registry', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    _resetSinksForTesting();
    logMessages = [];
    mkdirSync(testDir, { recursive: true });
  });

  afterEach(() => {
    try { rmSync(testDir, { recursive: true, force: true }); } catch {}
  });

  // =========================================================================
  // loadPluginSinkConfigs
  // =========================================================================
  describe('loadPluginSinkConfigs', () => {
    it('returns empty array when plugin.json does not exist', () => {
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('returns empty array when plugin.json has no telemetry section', () => {
      writePluginJson({ name: 'test-plugin', version: '1.0.0' });
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('returns empty array when telemetry has no sinks', () => {
      writePluginJson({ telemetry: {} });
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('returns empty array when sinks is not an array', () => {
      writePluginJson({ telemetry: { sinks: 'not-an-array' } });
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('parses valid http sink config', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://metrics.example.com/ingest', token: 'tok-123' },
          ],
        },
      });
      const configs = loadPluginSinkConfigs();
      expect(configs).toHaveLength(1);
      expect(configs[0].type).toBe('http');
      expect(configs[0].url).toBe('https://metrics.example.com/ingest');
      expect(configs[0].token).toBe('tok-123');
    });

    it('filters out invalid sink configs (missing url)', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', token: 'tok-123' }, // missing url
            { type: 'http', url: 'https://valid.com', token: 'tok-456' },
          ],
        },
      });
      expect(loadPluginSinkConfigs()).toHaveLength(1);
    });

    it('filters out invalid sink configs (missing token)', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://valid.com' }, // missing token
          ],
        },
      });
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('filters out unsupported sink types', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'kafka', url: 'kafka://broker:9092', token: 'tok' },
          ],
        },
      });
      expect(loadPluginSinkConfigs()).toEqual([]);
    });

    it('handles malformed plugin.json gracefully', () => {
      writeFileSync(join(testDir, 'plugin.json'), '{{invalid json', 'utf8');
      expect(loadPluginSinkConfigs()).toEqual([]);
      expect(logMessages.some(m => m.includes('Failed to parse'))).toBe(true);
    });

    it('preserves optional name and hmacSecret fields', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            {
              type: 'http',
              name: 'my-custom-sink',
              url: 'https://metrics.example.com/ingest',
              token: 'tok-123',
              hmacSecret: 'hmac-secret-456',
            },
          ],
        },
      });
      const configs = loadPluginSinkConfigs();
      expect(configs[0].name).toBe('my-custom-sink');
      expect(configs[0].hmacSecret).toBe('hmac-secret-456');
    });
  });

  // =========================================================================
  // loadUserSinkConfigs
  // =========================================================================
  describe('loadUserSinkConfigs', () => {
    it('returns empty array when settings.local.json does not exist', () => {
      expect(loadUserSinkConfigs()).toEqual([]);
    });

    it('parses valid user sink config', () => {
      writeSettingsLocalJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://user-metrics.example.com', token: 'user-tok' },
          ],
        },
      });
      const configs = loadUserSinkConfigs();
      expect(configs).toHaveLength(1);
      expect(configs[0].url).toBe('https://user-metrics.example.com');
    });

    it('handles malformed settings.local.json gracefully', () => {
      const claudeDir = join(testDir, '.claude');
      mkdirSync(claudeDir, { recursive: true });
      writeFileSync(join(claudeDir, 'settings.local.json'), 'not-json', 'utf8');
      expect(loadUserSinkConfigs()).toEqual([]);
    });
  });

  // =========================================================================
  // registerAllSinks
  // =========================================================================
  describe('registerAllSinks', () => {
    it('registers JSONL sink (always-on)', () => {
      registerAllSinks();
      // JSONL is always registered even without HTTP config
      expect(sinkCount()).toBeGreaterThanOrEqual(1);
    });

    it('does not register HTTP sink when URL is not configured', () => {
      registerAllSinks();
      // Only JSONL should be registered (webhook URL is mocked to undefined)
      expect(sinkCount()).toBe(1);
    });

    it('is idempotent — calling twice does not duplicate sinks', () => {
      registerAllSinks();
      const first = sinkCount();
      registerAllSinks();
      expect(sinkCount()).toBe(first);
    });

    it('registers plugin-configured sinks', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://plugin-sink.example.com', token: 'ptok' },
          ],
        },
      });
      registerAllSinks();
      // JSONL + plugin sink
      expect(sinkCount()).toBe(2);
    });

    it('registers user-configured sinks alongside built-in', () => {
      writeSettingsLocalJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://user-sink.example.com', token: 'utok' },
          ],
        },
      });
      registerAllSinks();
      // JSONL + user sink
      expect(sinkCount()).toBe(2);
    });

    it('registers both plugin and user sinks (additive)', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', name: 'plugin-metrics', url: 'https://plugin.example.com', token: 'ptok' },
          ],
        },
      });
      writeSettingsLocalJson({
        telemetry: {
          sinks: [
            { type: 'http', name: 'user-metrics', url: 'https://user.example.com', token: 'utok' },
          ],
        },
      });
      registerAllSinks();
      // JSONL + plugin + user
      expect(sinkCount()).toBe(3);
    });

    it('deduplicates sinks with same name (plugin wins over user)', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', name: 'shared-name', url: 'https://plugin.example.com', token: 'ptok' },
          ],
        },
      });
      writeSettingsLocalJson({
        telemetry: {
          sinks: [
            { type: 'http', name: 'shared-name', url: 'https://user.example.com', token: 'utok' },
          ],
        },
      });
      registerAllSinks();
      // JSONL + shared-name (only one, plugin registered first)
      expect(sinkCount()).toBe(2);
    });

    it('derives sink name from URL hostname when name not provided', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'https://metrics.acme.com/v1/ingest', token: 'tok' },
          ],
        },
      });
      registerAllSinks();
      expect(logMessages.some(m => m.includes('http-metrics.acme.com'))).toBe(true);
    });

    it('handles invalid URL in sink config gracefully', () => {
      writePluginJson({
        telemetry: {
          sinks: [
            { type: 'http', url: 'not-a-valid-url', token: 'tok' },
          ],
        },
      });
      // Should not throw
      registerAllSinks();
      // JSONL + the custom sink (name falls back to http-custom)
      expect(sinkCount()).toBe(2);
    });
  });
});
